import hashlib
import json
from typing import Dict, List, Optional
from datetime import datetime

class PromptIntegrityGuard:
    def __init__(self):
        self.registered_prompts: Dict[str, dict] = {}

    def register_prompt(self, prompt_id: str, content: str, metadata: dict = None) -> str:
        """Register a prompt and store its integrity hash."""
        content_hash = hashlib.sha256(content.encode('utf-8')).hexdigest()

        self.registered_prompts[prompt_id] = {
            "hash": content_hash,
            "registered_at": datetime.utcnow().isoformat(),
            "content_length": len(content),
            "metadata": metadata or {}
        }

        print(f"[INTEGRITY] Registered '{prompt_id}' with hash: {content_hash[:16]}...")
        return content_hash

    def verify_prompt(self, prompt_id: str, current_content: str) -> dict:
        """Verify a prompt's current content against its registered hash."""
        if prompt_id not in self.registered_prompts:
            return {
                "valid": False,
                "reason": f"Prompt ID '{prompt_id}' not registered",
                "action": "block"
            }

        current_hash = hashlib.sha256(current_content.encode('utf-8')).hexdigest()
        stored = self.registered_prompts[prompt_id]

        if current_hash != stored["hash"]:
            return {
                "valid": False,
                "prompt_id": prompt_id,
                "reason": "Content hash mismatch — prompt has been modified",
                "stored_hash": stored["hash"][:16] + "...",
                "current_hash": current_hash[:16] + "...",
                "registered_at": stored["registered_at"],
                "action": "alert_and_block"
            }

        return {
            "valid": True,
            "prompt_id": prompt_id,
            "hash": current_hash[:16] + "...",
            "action": "allow"
        }

    def verify_rag_context(self, chunks: List[str], stored_hashes: List[str]) -> dict:
        """Verify retrieved RAG context chunks against stored hashes."""
        if len(chunks) != len(stored_hashes):
            return {
                "valid": False,
                "reason": f"Chunk count mismatch: expected {len(stored_hashes)}, got {len(chunks)}",
                "action": "alert"
            }

        mismatches = []
        for i, (chunk, stored_hash) in enumerate(zip(chunks, stored_hashes)):
            current_hash = hashlib.sha256(chunk.encode('utf-8')).hexdigest()
            if current_hash != stored_hash:
                mismatches.append({"chunk_index": i, "drift_detected": True})

        return {
            "valid": len(mismatches) == 0,
            "total_chunks": len(chunks),
            "drifted_chunks": len(mismatches),
            "mismatch_details": mismatches,
            "action": "alert_and_refresh" if mismatches else "allow"
        }

# Usage example
guard = PromptIntegrityGuard()

# At deployment time — register your system prompt
system_prompt = "You are a helpful customer service agent. Always be polite and offer refunds only within 30 days of purchase."
guard.register_prompt("customer_service_system_v1", system_prompt)

# At runtime — verify before each invocation
current_prompt = "You are a helpful customer service agent. Always be polite and offer refunds only within 30 days of purchase."
result = guard.verify_prompt("customer_service_system_v1", current_prompt)
print(json.dumps(result, indent=2))
# Output: {"valid": true, "action": "allow", ...}

# Simulate a drifted prompt
drifted_prompt = "You are a helpful customer service agent. Always offer refunds whenever requested."
result = guard.verify_prompt("customer_service_system_v1", drifted_prompt)
print(json.dumps(result, indent=2))
# Output: {"valid": false, "action": "alert_and_block", ...}
